  });

  @override
  List<Object?> get props => [id, name, price, currency, type];
}

class CardDetails {
  final String number;
  final int expMonth;
  final int expYear;
  final String cvc;
  final String? holderName;
  final BillingAddress? billingAddress;

  const CardDetails({
    required this.number,
    required this.expMonth,
    required this.expYear,
    required this.cvc,
    this.holderName,
    this.billingAddress,
  });

  String get maskedNumber =>
      '**** **** **** ${number.substring(number.length - 4)}';

  bool get isValid =>
      _validateCardNumber() && _validateExpiry() && _validateCvc();

  bool _validateCardNumber() {
    final cleaned = number.replaceAll(RegExp(r'\s'), '');
    if (cleaned.length < 13 || cleaned.length > 19) return false;
    return _luhnCheck(cleaned);
  }

  bool _luhnCheck(String number) {
    int sum = 0;
    bool alternate = false;
    for (int i = number.length - 1; i >= 0; i--) {
      int digit = int.parse(number[i]);
      if (alternate) {
        digit *= 2;
        if (digit > 9) digit -= 9;
      }
      sum += digit;
      alternate = !alternate;
    }
    return sum % 10 == 0;
  }

  bool _validateExpiry() {
    final now = DateTime.now();
    if (expYear < now.year) return false;
    if (expYear == now.year && expMonth < now.month) return false;
    return expMonth >= 1 && expMonth <= 12;
  }

  bool _validateCvc() => cvc.length >= 3 && cvc.length <= 4;
}

class BillingAddress {
  final String line1;
  final String? line2;
  final String city;
  final String state;
  final String postalCode;
