import 'dart:convert';
import 'dart:math';
import 'package:crypto/crypto.dart';
import 'package:flutter_secure_storage/flutter_secure_storage.dart';

class PaymentSecurity {
  static final PaymentSecurity _instance = PaymentSecurity._internal();
  factory PaymentSecurity() => _instance;
  PaymentSecurity._internal();

  final FlutterSecureStorage _secureStorage = const FlutterSecureStorage(
    aOptions: AndroidOptions(encryptedSharedPreferences: true),
    iOptions: IOSOptions(
      accessibility: KeychainAccessibility.first_unlock_this_device,
    ),
  );

  // PCI DSS: Never store full card numbers - tokenize immediately
  Future<String> tokenizeCard(CardDetails card) async {
    final token = _generateSecureToken();
    // Store only last 4 digits and token mapping
    await _secureStorage.write(
      key: 'card_token_$token',
      value: jsonEncode({
        'last4': card.number.substring(card.number.length - 4),
        'expMonth': card.expMonth,
        'expYear': card.expYear,
        'holderName': card.holderName,
        'createdAt': DateTime.now().toIso8601String(),
      }),
    );
    return token;
  }

  Future<void> deleteToken(String token) async {
    await _secureStorage.delete(key: 'card_token_$token');
  }

  Future<void> storeApiKey(String key, String value) async {
    await _secureStorage.write(key: 'api_key_$key', value: value);
  }

  Future<String?> getApiKey(String key) async {
    return await _secureStorage.read(key: 'api_key_$key');
  }

  String _generateSecureToken() {
    final random = Random.secure();
    final values = List<int>.generate(32, (_) => random.nextInt(256));
    return base64Url.encode(values);
  }

  String hashTransactionData(Map<String, dynamic> data) {
    final jsonStr = jsonEncode(data);
    return sha256.convert(utf8.encode(jsonStr)).toString();
  }

  String generateIdempotencyKey() {
    final timestamp = DateTime.now().millisecondsSinceEpoch;
    final random = Random.secure().nextInt(999999);
    return sha256
        .convert(utf8.encode('$timestamp-$random'))
        .toString()
        .substring(0, 32);
  }

  bool verifyWebhookSignature(
    String payload,
    String signature,
    String secret,
  ) {
    final hmac = Hmac(sha256, utf8.encode(secret));
    final digest = hmac.convert(utf8.encode(payload));
    return digest.toString() == signature;
  }

  Future<void> clearAllSecureData() async {
    await _secureStorage.deleteAll();
  }
}

