import 'dart:convert';

class TransactionLog {
  final String transactionId;
  final String action;
  final DateTime timestamp;
  final Map<String, dynamic>? details;
  final String? error;

  TransactionLog({
    required this.transactionId,
    required this.action,
    required this.timestamp,
    this.details,
    this.error,
  });

  Map<String, dynamic> toJson() => {
    'transactionId': transactionId,
    'action': action,
    'timestamp': timestamp.toIso8601String(),
    'details': details,
    'error': error,
  };
}

class TransactionLogger {
  static final TransactionLogger _instance = TransactionLogger._internal();
  factory TransactionLogger() => _instance;
  TransactionLogger._internal();

  final List<TransactionLog> _logs = [];
  void Function(TransactionLog)? onLog;

  void log(
    String transactionId,
    String action, {
    Map<String, dynamic>? details,
    String? error,
  }) {
    // PCI: Sanitize any sensitive data before logging
    final sanitizedDetails = details != null ? _sanitize(details) : null;

    final logEntry = TransactionLog(
      transactionId: transactionId,
      action: action,
      timestamp: DateTime.now(),
      details: sanitizedDetails,
      error: error,
    );

    _logs.add(logEntry);
    onLog?.call(logEntry);

    // In production, send to secure logging service
    _sendToRemoteLogger(logEntry);
  }

  Map<String, dynamic> _sanitize(Map<String, dynamic> data) {
    final sanitized = Map<String, dynamic>.from(data);
    const sensitiveKeys = [
      'cardNumber',
      'cvc',
      'cvv',
      'password',
      'secret',
      'token',
      'apiKey',
    ];

    for (final key in sanitized.keys.toList()) {
      if (sensitiveKeys.any(
        (sk) => key.toLowerCase().contains(sk.toLowerCase()),
      )) {
        sanitized[key] = '***REDACTED***';
      }
    }
    return sanitized;
  }

  Future<void> _sendToRemoteLogger(TransactionLog log) async {
    // TODO: Implement remote logging to your secure backend
    // Example: Send to your audit trail API
    print(
      '[PAYMENT LOG] ${log.action}: ${jsonEncode(log.toJson())}',
    );
  }

  List<TransactionLog> getLogsForTransaction(String transactionId) {
    return _logs.where((l) => l.transactionId == transactionId).toList();
  }

  List<TransactionLog> getRecentLogs({int limit = 50}) {
    final sorted = List<TransactionLog>.from(_logs)
      ..sort((a, b) => b.timestamp.compareTo(a.timestamp));
    return sorted.take(limit).toList();
  }
}

