// lib/payment/gateways/stripe_gateway.dart
import 'dart:convert';
import 'package:http/http.dart' as http;
import 'package:uuid/uuid.dart';

class StripeGateway implements PaymentGateway {
  String? _publishableKey;
  String? _secretKey; // Should be on backend only - here for demo
  String? _baseUrl;
  final _uuid = const Uuid();
  final _security = PaymentSecurity();
  final _logger = TransactionLogger();

  @override
  Future<void> initialize(Map<String, dynamic> config) async {
    _publishableKey = config['publishableKey'];
    _baseUrl = config['backendUrl'] ?? 'https://api.stripe.com/v1';

    // In production, secret key should NEVER be in the client
    // All server-side operations go through your backend
    _secretKey = await _security.getApiKey('stripe_secret');

    _logger.log('SYSTEM', 'stripe_initialized', details: {
      'publishableKey': _publishableKey?.substring(0, 10),
    });
  }

  @override
  Future<PaymentResult> processPayment(
    PaymentItem item, {
    CardDetails? card,
  }) async {
    final transactionId = _uuid.v4();
    final idempotencyKey = _security.generateIdempotencyKey();

    _logger.log(transactionId, 'payment_initiated', details: {
      'amount': item.price,
      'currency': item.currency,
      'itemId': item.id,
    });

    try {
      // Step 1: Create payment intent on your backend
      final paymentIntent = await _createPaymentIntent(
        amount: (item.price * 100).round(), // Stripe uses cents
        currency: item.currency.toLowerCase(),
        idempotencyKey: idempotencyKey,
        metadata: {
          'itemId': item.id,
          'itemName': item.name,
          'transactionId': transactionId,
        },
      );

      if (paymentIntent == null) {
        throw PaymentException(
          'Failed to create payment intent',
          code: 'INTENT_CREATION_FAILED',
        );
      }

      // Step 2: Confirm payment (in real app, use Stripe SDK)
      final result = await _confirmPayment(
        paymentIntentId: paymentIntent['id'],
        card: card,
      );

      final status =
          result['status'] == 'succeeded'
              ? PaymentStatus.completed
              : result['status'] == 'requires_action'
              ? PaymentStatus.requiresAction
              : PaymentStatus.failed;

      _logger.log(transactionId, 'payment_completed', details: {
        'status': status.name,
        'stripeId': paymentIntent['id'],
      });

      return PaymentResult(
        transactionId: transactionId,
        status: status,
        amount: item.price,
        currency: item.currency,
        method: PaymentMethod.stripe,
        timestamp: DateTime.now(),
        receiptData: jsonEncode(result),
        metadata: {
          'stripePaymentIntentId': paymentIntent['id'],
          'idempotencyKey': idempotencyKey,
        },
      );
    } catch (e) {
      _logger.log(
        transactionId,
        'payment_failed',
        error: e.toString(),
      );

      return PaymentResult(
        transactionId: transactionId,
        status: PaymentStatus.failed,
        amount: item.price,
        currency: item.currency,
        method: PaymentMethod.stripe,
        timestamp: DateTime.now(),
        errorMessage: e.toString(),
      );
    }
  }

  Future<Map<String, dynamic>?> _createPaymentIntent({
    required int amount,
    required String currency,
    required String idempotencyKey,
    Map<String, String>? metadata,
  }) async {
    // In production, this call goes to YOUR backend, not directly to Stripe
    try {
      final response = await http.post(
        Uri.parse('$_baseUrl/payment_intents'),
        headers: {
          'Authorization': 'Bearer $_secretKey',
          'Content-Type': 'application/x-www-form-urlencoded',
          'Idempotency-Key': idempotencyKey,
        },
        body: {
          'amount': amount.toString(),
          'currency': currency,
          'automatic_payment_methods[enabled]': 'true',
          if (metadata != null)
            ...metadata.map(
              (k, v) => MapEntry('metadata[$k]', v),
            ),
        },
      );

      if (response.statusCode == 200) {
        return jsonDecode(response.body);
      }
      return null;
    } catch (e) {
      throw PaymentException(
        'Network error creating payment intent',
        code: 'NETWORK_ERROR',
      );
    }
  }

  Future<Map<String, dynamic>> _confirmPayment({
    required String paymentIntentId,
    CardDetails? card,
  }) async {
    // In production, use Stripe SDK's confirmPayment
    // This is a simplified version
    try {
      final response = await http.post(
        Uri.parse('$_baseUrl/payment_intents/$paymentIntentId/confirm'),
        headers: {
          'Authorization': 'Bearer $_secretKey',
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: {
          'return_url': 'yourapp://stripe-redirect',
        },
      );

      return jsonDecode(response.body);
    } catch (e) {
      throw PaymentException(
        'Failed to confirm payment',
        code: 'CONFIRM_FAILED',
      );
    }
  }

  @override
  Future<PaymentResult> processSubscription(PaymentItem item) async {
    final transactionId = _uuid.v4();

    _logger.log(transactionId, 'subscription_initiated', details: {
      'itemId': item.id,
      'period': item.subscriptionPeriod,
    });

    try {
      // Create subscription via your backend
      final response = await http.post(
        Uri.parse('$_baseUrl/subscriptions'),
        headers: {
          'Authorization': 'Bearer $_secretKey',
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: {
          'items[0][price]': item.id,
        },
      );

      final result = jsonDecode(response.body);

      return PaymentResult(
        transactionId: transactionId,
        status:
            result['status'] == 'active'
                ? PaymentStatus.completed
                : PaymentStatus.pending,
        amount: item.price,
        currency: item.currency,
        method: PaymentMethod.stripe,
        timestamp: DateTime.now(),
        metadata: {'subscriptionId': result['id']},
      );
    } catch (e) {
      return PaymentResult(
        transactionId: transactionId,
        status: PaymentStatus.failed,
        amount: item.price,
        currency: item.currency,
        method: PaymentMethod.stripe,
        timestamp: DateTime.now(),
        errorMessage: e.toString(),
      );
    }
  }

  @override
  Future<PaymentResult> refund(
    String transactionId, {
    double? amount,
  }) async {
    final refundId = _uuid.v4();

    _logger.log(refundId, 'refund_initiated', details: {
      'originalTransactionId': transactionId,
      'amount': amount,
    });

    try {
      final body = <String, String>{
        'payment_intent': transactionId,
      };
      if (amount != null) {
        body['amount'] = (amount * 100).round().toString();
      }

      final response = await http.post(
        Uri.parse('$_baseUrl/refunds'),
        headers: {
          'Authorization': 'Bearer $_secretKey',
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: body,
      );

      final result = jsonDecode(response.body);

      return PaymentResult(
        transactionId: refundId,
        status:
            result['status'] == 'succeeded'
                ? PaymentStatus.refunded
                : PaymentStatus.failed,
        amount: amount ?? 0,
        currency: result['currency'] ?? 'USD',
        method: PaymentMethod.stripe,
        timestamp: DateTime.now(),
        metadata: {'refundId': result['id']},
      );
    } catch (e) {
      return PaymentResult(
        transactionId: refundId,
        status: PaymentStatus.failed,
        amount: amount ?? 0,
        currency: 'USD',
        method: PaymentMethod.stripe,
        timestamp: DateTime.now(),
        errorMessage: e.toString(),
      );
    }
  }

  @override
  Future<bool> verifyReceipt(String receiptData) async {
    // Verify payment on your backend
    try {
      final data = jsonDecode(receiptData);
      final response = await http.get(
        Uri.parse('$_baseUrl/payment_intents/${data['id']}'),
        headers: {'Authorization': 'Bearer $_secretKey'},
      );

      final result = jsonDecode(response.body);
      return result['status'] == 'succeeded';
    } catch (e) {
      return false;
    }
  }

  @override
  Future<void> dispose() async {
    _logger.log('SYSTEM', 'stripe_disposed');
  }
}

