// lib/payment/gateways/iap_gateway.dart
import 'dart:async';
import 'dart:io';
import 'package:in_app_purchase/in_app_purchase.dart';
import 'package:in_app_purchase_storekit/in_app_purchase_storekit.dart';
import 'package:in_app_purchase_android/in_app_purchase_android.dart';

class InAppPurchaseGateway implements PaymentGateway {
  final InAppPurchase _iap = InAppPurchase.instance;
  StreamSubscription<List<PurchaseDetails>>? _subscription;
  final _logger = TransactionLogger();
  final _security = PaymentSecurity();

  final Map<String, Completer<PaymentResult>> _pendingPurchases = {};
  final Map<String, ProductDetails> _products = {};

  @override
  Future<void> initialize(Map<String, dynamic> config) async {
    final available = await _iap.isAvailable();
    if (!available) {
      throw PaymentException(
        'In-app purchases not available',
        code: 'IAP_UNAVAILABLE',
      );
    }

    // Listen to purchase updates
    _subscription = _iap.purchaseStream.listen(
      _handlePurchaseUpdate,
      onDone: () => _subscription?.cancel(),
      onError: (error) {
        _logger.log('SYSTEM', 'iap_stream_error', error: error.toString());
      },
    );

    // Load products
    final productIds = Set<String>.from(config['productIds'] ?? []);
    if (productIds.isNotEmpty) {
      await _loadProducts(productIds);
    }

    _logger.log('SYSTEM', 'iap_initialized', details: {
      'platform': Platform.isIOS ? 'iOS' : 'Android',
      'productsLoaded': _products.length,
    });
  }

  Future<void> _loadProducts(Set<String> productIds) async {
    final response = await _iap.queryProductDetails(productIds);

    if (response.error != null) {
      _logger.log('SYSTEM', 'product_query_error', error: response.error!.message);
    }

    if (response.notFoundIDs.isNotEmpty) {
      _logger.log('SYSTEM', 'products_not_found', details: {
        'ids': response.notFoundIDs,
      });
    }

    for (final product in response.productDetails) {
      _products[product.id] = product;
    }
  }

  void _handlePurchaseUpdate(List<PurchaseDetails> purchases) {
    for (final purchase in purchases) {
      _processPurchase(purchase);
    }
  }

  Future<void> _processPurchase(PurchaseDetails purchase) async {
    final transactionId =
        purchase.purchaseID ?? DateTime.now().millisecondsSinceEpoch.toString();

    _logger.log(transactionId, 'purchase_update', details: {
      'productId': purchase.productID,
      'status': purchase.status.name,
    });

    switch (purchase.status) {
      case PurchaseStatus.purchased:
      case PurchaseStatus.restored:
        // CRITICAL: Verify receipt on your server
        final isValid = await _verifyPurchaseOnServer(purchase);

        if (isValid) {
          // Complete the purchase
          if (purchase.pendingCompletePurchase) {
            await _iap.completePurchase(purchase);
          }

          _completePendingPurchase(
            purchase.productID,
            PaymentResult(
              transactionId: transactionId,
              status: PaymentStatus.completed,
              amount: 0, // Price from product details
              currency: 'USD',
              method: PaymentMethod.inAppPurchase,
              timestamp: DateTime.now(),
              receiptData: purchase.verificationData.serverVerificationData,
              metadata: {
                'productId': purchase.productID,
                'source': purchase.verificationData.source,
              },
            ),
          );
        } else {
          _completePendingPurchase(
            purchase.productID,
            PaymentResult(
              transactionId: transactionId,
              status: PaymentStatus.failed,
              amount: 0,
              currency: 'USD',
              method: PaymentMethod.inAppPurchase,
              timestamp: DateTime.now(),
              errorMessage: 'Receipt verification failed',
            ),
          );
        }
        break;

      case PurchaseStatus.error:
        _completePendingPurchase(
          purchase.productID,
          PaymentResult(
            transactionId: transactionId,
            status: PaymentStatus.failed,
            amount: 0,
            currency: 'USD',
            method: PaymentMethod.inAppPurchase,
            timestamp: DateTime.now(),
            errorMessage: purchase.error?.message ?? 'Unknown error',
          ),
        );
        break;

      case PurchaseStatus.canceled:
        _completePendingPurchase(
          purchase.productID,
          PaymentResult(
            transactionId: transactionId,
            status: PaymentStatus.cancelled,
            amount: 0,
            currency: 'USD',
            method: PaymentMethod.inAppPurchase,
            timestamp: DateTime.now(),
          ),
        );
        break;

      case PurchaseStatus.pending:
        _logger.log(transactionId, 'purchase_pending');
        break;
    }
  }

  void _completePendingPurchase(String productId, PaymentResult result) {
    final completer = _pendingPurchases.remove(productId);
    if (completer != null && !completer.isCompleted) {
      completer.complete(result);
    }
  }

  Future<bool> _verifyPurchaseOnServer(PurchaseDetails purchase) async {
    // CRITICAL: Always verify receipts on your server
    // Never trust client-side verification alone
    try {
      final receiptData = purchase.verificationData.serverVerificationData;
      return await verifyReceipt(receiptData);
    } catch (e) {
      _logger.log(
        purchase.purchaseID ?? 'unknown',
        'receipt_verification_error',
        error: e.toString(),
      );
      return false;
    }
  }

  @override
  Future<PaymentResult> processPayment(
    PaymentItem item, {
    CardDetails? card,
  }) async {
    final product = _products[item.id];
    if (product == null) {
      // Try loading the product
      await _loadProducts({item.id});
      final loadedProduct = _products[item.id];
      if (loadedProduct == null) {
        return PaymentResult(
          transactionId: '',
          status: PaymentStatus.failed,
          amount: item.price,
          currency: item.currency,
          method: PaymentMethod.inAppPurchase,
          timestamp: DateTime.now(),
          errorMessage: 'Product not found: ${item.id}',
        );
      }
    }

    final completer = Completer<PaymentResult>();
    _pendingPurchases[item.id] = completer;

    final purchaseParam = PurchaseParam(productDetails: _products[item.id]!);

    bool success;
    if (item.type == TransactionType.consumable) {
      success = await _iap.buyConsumable(purchaseParam: purchaseParam);
    } else {
      success = await _iap.buyNonConsumable(purchaseParam: purchaseParam);
    }

    if (!success) {
      _pendingPurchases.remove(item.id);
      return PaymentResult(
        transactionId: '',
        status: PaymentStatus.failed,
        amount: item.price,
        currency: item.currency,
        method: PaymentMethod.inAppPurchase,
        timestamp: DateTime.now(),
        errorMessage: 'Failed to initiate purchase',
      );
    }

    // Wait for purchase stream to complete
    return completer.future.timeout(
      const Duration(minutes: 5),
      onTimeout: () {
        _pendingPurchases.remove(item.id);
        return PaymentResult(
          transactionId: '',
          status: PaymentStatus.failed,
          amount: item.price,
          currency: item.currency,
          method: PaymentMethod.inAppPurchase,
          timestamp: DateTime.now(),
          errorMessage: 'Purchase timed out',
        );
      },
    );
  }

  @override
  Future<PaymentResult> processSubscription(PaymentItem item) async {
    return processPayment(
      PaymentItem(
        id: item.id,
        name: item.name,
        description: item.description,
        price: item.price,
        currency: item.currency,
        type: TransactionType.subscription,
        subscriptionPeriod: item.subscriptionPeriod,
      ),
    );
  }

  Future<List<PaymentResult>> restorePurchases() async {
    await _iap.restorePurchases();
    // Results come through the purchase stream
    return [];
  }

  @override
  Future<PaymentResult> refund(
    String transactionId, {
    double? amount,
  }) async {
    // IAP refunds are handled through App Store / Play Store
    return PaymentResult(
      transactionId: transactionId,
      status: PaymentStatus.failed,
      amount: amount ?? 0,
      currency: 'USD',
      method: PaymentMethod.inAppPurchase,
      timestamp: DateTime.now(),
      errorMessage: 'Refunds must be processed through the app store',
    );
  }

  @override
  Future<bool> verifyReceipt(String receiptData) async {
    // Send to YOUR backend for server-side verification
    // Your backend should verify with Apple/Google servers
    try {
      final response = await http.post(
        Uri.parse('https://your-backend.com/api/verify-receipt'),
        headers: {'Content-Type': 'application/json'},
        body: jsonEncode({
          'receipt': receiptData,
          'platform': Platform.isIOS ? 'ios' : 'android',
        }),
      );

      if (response.statusCode == 200) {
        final result = jsonDecode(response.body);
        return result['valid'] == true;
      }
      return false;
    } catch (e) {
      _logger.log(
        'SYSTEM',
        'receipt_verification_network_error',
        error: e.toString(),
      );
      return false;
    }
  }

  List<ProductDetails> get availableProducts => _products.values.toList();

  @override
  Future<void> dispose() async {
    await _subscription?.cancel();
    _pendingPurchases.clear();
    _logger.log('SYSTEM', 'iap_disposed');
  }
}

// ---- Mobile Wallet Gateway (Apple Pay / Google Pay) ----

// lib/payment/gateways/wallet_gateway.dart
import 'dart:io';

class MobileWalletGateway implements PaymentGateway {
  final _logger = TransactionLogger();
  final _security = PaymentSecurity();
  Map<String, dynamic>? _config;

  // Apple Pay configuration
  static const String _applePayMerchantId = 'merchant.com.yourapp';

  // Google Pay configuration
  static const int _googlePayEnvironment = 1; // 1 = Production, 3 = Test

  @override
  Future<void> initialize(Map<String, dynamic> config) async {
    _config = config;
    _logger.log('SYSTEM', 'wallet_initialized', details: {
      'platform': Platform.isIOS ? 'Apple Pay' : 'Google Pay',
    });
  }

  Future<bool> isWalletAvailable() async {
    // Check if Apple Pay / Google Pay is available on device
    // In real implementation, use the pay package
    if (Platform.isIOS) {
      return await _checkApplePayAvailability();
    } else {
      return await _checkGooglePayAvailability();
    }
  }

  Future<bool> _checkApplePayAvailability() async {
    // Use PKPaymentAuthorizationController.canMakePayments
    return true; // Simplified
  }

  Future<bool> _checkGooglePayAvailability() async {
    // Use IsReadyToPayRequest
    return true; // Simplified
  }

  @override
  Future<PaymentResult> processPayment(
    PaymentItem item, {
    CardDetails? card,
  }) async {
    final transactionId = const Uuid().v4();

    _logger.log(transactionId, 'wallet_payment_initiated', details: {
      'amount': item.price,
      'currency': item.currency,
      'platform': Platform.isIOS ? 'apple_pay' : 'google_pay',
    });

    try {
      if (!await isWalletAvailable()) {
        throw PaymentException(
          'Mobile wallet not available',
          code: 'WALLET_UNAVAILABLE',
        );
      }

      Map<String, dynamic> paymentData;

      if (Platform.isIOS) {
        paymentData = await _processApplePay(item);
      } else {
        paymentData = await _processGooglePay(item);
      }

      // Send the payment token to your backend / Stripe
      final result = await _processWalletToken(paymentData, item);

      _logger.log(transactionId, 'wallet_payment_completed', details: {
        'status': result.status.name,
      });

      return result.copyWith(transactionId: transactionId);
    } catch (e) {
      _logger.log(
        transactionId,
        'wallet_payment_failed',
        error: e.toString(),
      );

      return PaymentResult(
        transactionId: transactionId,
        status:
            e is PaymentCancelledException
                ? PaymentStatus.cancelled
                : PaymentStatus.failed,
        amount: item.price,
        currency: item.currency,
        method:
            Platform.isIOS ? PaymentMethod.applePay : PaymentMethod.googlePay,
        timestamp: DateTime.now(),
        errorMessage: e.toString(),
      );
    }
  }

  Future<Map<String, dynamic>> _processApplePay(PaymentItem item) async {
    // In real implementation, use the pay package or PassKit
    // This creates the Apple Pay payment sheet
    final paymentRequest = {
      'merchantIdentifier': _applePayMerchantId,
      'supportedNetworks': ['visa', 'masterCard', 'amex', 'discover'],
      'merchantCapabilities': ['3DS', 'debit', 'credit'],
      'countryCode': 'US',
      'currencyCode': item.currency,
      'paymentSummaryItems': [
        {
          'label': item.name,
          'amount': item.price.toStringAsFixed(2),
          'type': 'final',
        },
      ],
    };

    // Present Apple Pay sheet and get token
    // final result = await Pay.withAssets(['apple_pay_config.json']).showPaymentSelector(...)

    return {
      'token': 'apple_pay_token_placeholder',
      'paymentMethod': 'apple_pay',
    };
  }

  Future<Map<String, dynamic>> _processGooglePay(PaymentItem item) async {
    // In real implementation, use the pay package
    final paymentRequest = {
      'apiVersion': 2,
      'apiVersionMinor': 0,
      'allowedPaymentMethods': [
        {
          'type': 'CARD',
          'parameters': {
            'allowedAuthMethods': ['PAN_ONLY', 'CRYPTOGRAM_3DS'],
            'allowedCardNetworks': ['VISA', 'MASTERCARD', 'AMEX', 'DISCOVER'],
          },
          'tokenizationSpecification': {
            'type': 'PAYMENT_GATEWAY',
            'parameters': {
              'gateway': 'stripe',
              'stripe:version': '2023-10-16',
              'stripe:publishableKey': _config?['stripePublishableKey'],
            },
          },
        },
      ],
      'transactionInfo': {
        'totalPriceStatus': 'FINAL',
        'totalPrice': item.price.toStringAsFixed(2),
        'currencyCode': item.currency,
        'countryCode': 'US',
      },
      'merchantInfo': {
        'merchantName': _config?['merchantName'] ?? 'Your App',
      },
    };

    return {
      'token': 'google_pay_token_placeholder',
      'paymentMethod': 'google_pay',
    };
  }

  Future<PaymentResult> _processWalletToken(
    Map<String, dynamic> paymentData,
    PaymentItem item,
  ) async {
    // Send the wallet token to your backend to create a charge
    try {
      final response = await http.post(
        Uri.parse('${_config?['backendUrl']}/api/process-wallet-payment'),
        headers: {'Content-Type': 'application/json'},
        body: jsonEncode({
          'token': paymentData['token'],
          'amount': (item.price * 100).round(),
          'currency': item.currency.toLowerCase(),
          'description': item.name,
        }),
      );

      if (response.statusCode == 200) {
        final result = jsonDecode(response.body);
        return PaymentResult(
          transactionId: result['transactionId'] ?? '',
          status: PaymentStatus.completed,
          amount: item.price,
          currency: item.currency,
          method:
              Platform.isIOS
                  ? PaymentMethod.applePay
                  : PaymentMethod.googlePay,
          timestamp: DateTime.now(),
          receiptData: response.body,
        );
      }

      throw PaymentException(
        'Backend processing failed',
        code: 'BACKEND_ERROR',
      );
    } catch (e) {
      rethrow;
    }
  }

  @override
  Future<PaymentResult> processSubscription(PaymentItem item) async {
    // Wallet payments for subscriptions
    return processPayment(item);
  }

  @override
  Future<PaymentResult> refund(
    String transactionId, {
    double? amount,
  }) async {
    // Refunds go through your backend -> Stripe
    return PaymentResult(
      transactionId: transactionId,
      status: PaymentStatus.failed,
      amount: amount ?? 0,
      currency: 'USD',
      method: Platform.isIOS ? PaymentMethod.applePay : PaymentMethod.googlePay,
      timestamp: DateTime.now(),
      errorMessage: 'Process refund through payment gateway',
    );
  }

  @override
  Future<bool> verifyReceipt(String receiptData) async {
    return true; // Wallet payments verified through Stripe
  }

  @override
  Future<void> dispose() async {
    _logger.log('SYSTEM', 'wallet_disposed');
  }
}

// ---- Payment Result Extension ----

extension PaymentResultCopyWith on PaymentResult {
  PaymentResult copyWith({
    String? transactionId,
    PaymentStatus? status,
    double? amount,
    String? currency,
    PaymentMethod? method,
    DateTime? timestamp,
    String? errorMessage,
    String? receiptData,
    Map<String, dynamic>? metadata,
  }) {
    return PaymentResult(
      transactionId: transactionId ?? this.transactionId,
      status: status ?? this.status,
      amount: amount ?? this.amount,
      currency: currency ?? this.currency,
      method: method ?? this.method,
      timestamp: timestamp ?? this.timestamp,
      errorMessage: errorMessage ?? this.errorMessage,
      receiptData: receiptData ?? this.receiptData,
      metadata: metadata ?? this.metadata,
    );
  }
}

