// lib/payment/exceptions/payment_exceptions.dart
class PaymentException implements Exception {
  final String message;
  final String? code;
  final dynamic details;

  PaymentException(this.message, {this.code, this.details});

  @override
  String toString() => 'PaymentException($code): $message';
}

class PaymentCancelledException extends PaymentException {
  PaymentCancelledException() : super('Payment cancelled by user', code: 'CANCELLED');
}

class PaymentValidationException extends PaymentException {
  final List<String> errors;
  PaymentValidationException(this.errors)
      : super('Validation failed: ${errors.join(", ")}', code: 'VALIDATION');
}

// ---- Payment Manager (Main Entry Point) ----

// lib/payment/payment_manager.dart
import 'dart:async';

class PaymentManager {
  static final PaymentManager _instance = PaymentManager._internal();
  factory PaymentManager() => _instance;
  PaymentManager._internal();

  final Map<PaymentMethod, PaymentGateway> _gateways = {};
  final _logger = TransactionLogger();
  final _security = PaymentSecurity();

  bool _initialized = false;
  final _paymentController = StreamController<PaymentResult>.broadcast();

  Stream<PaymentResult> get paymentStream => _paymentController.stream;

  Future<void> initialize({
    required PaymentConfig config,
  }) async {
    if (_initialized) return;

    _logger.log('SYSTEM', 'payment_manager_initializing');

    // Initialize Stripe Gateway
    if (config.stripePublishableKey != null) {
      final stripeGateway = StripeGateway();
      await stripeGateway.initialize({
        'publishableKey': config.stripePublishableKey,
        'backendUrl': config.backendUrl,
      });
      _gateways[PaymentMethod.stripe] = stripeGateway;
      _gateways[PaymentMethod.creditCard] = stripeGateway;
    }

    // Initialize IAP Gateway
    if (config.iapProductIds != null && config.iapProductIds!.isNotEmpty) {
      final iapGateway = InAppPurchaseGateway();
      await iapGateway.initialize({
        'productIds': config.iapProductIds,
      });
      _gateways[PaymentMethod.inAppPurchase] = iapGateway;
    }

    // Initialize Mobile Wallet Gateway
    if (config.enableMobileWallet) {
      final walletGateway = MobileWalletGateway();
      await walletGateway.initialize({
        'stripePublishableKey': config.stripePublishableKey,
        'backendUrl': config.backendUrl,
        'merchantName': config.merchantName,
      });
      _gateways[PaymentMethod.applePay] = walletGateway;
      _gateways[PaymentMethod.googlePay] = walletGateway;
    }

    _initialized = true;
    _logger.log('SYSTEM', 'payment_manager_initialized', details: {
      'gateways': _gateways.keys.map((k) => k.name).toList(),
    });
  }

  Future<PaymentResult> processPayment({
    required PaymentItem item,
    required PaymentMethod method,
    CardDetails? card,
  }) async {
    _ensureInitialized();

    // Validate input
    _validatePaymentRequest(item, method, card);

    final gateway = _gateways[method];
    if (gateway == null) {
      throw PaymentException(
        'Payment method not configured: ${method.name}',
        code: 'METHOD_NOT_CONFIGURED',
      );
    }

    final result = await gateway.processPayment(item, card: card);
    _paymentController.add(result);
    return result;
  }

  Future<PaymentResult> processSubscription({
    required PaymentItem item,
    required PaymentMethod method,
  }) async {
    _ensureInitialized();

    final gateway = _gateways[method];
    if (gateway == null) {
      throw PaymentException(
        'Payment method not configured: ${method.name}',
        code: 'METHOD_NOT_CONFIGURED',
      );
    }

    final result = await gateway.processSubscription(item);
    _paymentController.add(result);
    return result;
  }

  Future<PaymentResult> refund({
    required String transactionId,
    required PaymentMethod method,
    double? amount,
  }) async {
    _ensureInitialized();

    final gateway = _gateways[method];
    if (gateway == null) {
      throw PaymentException(
        'Payment method not configured: ${method.name}',
        code: 'METHOD_NOT_CONFIGURED',
      );
    }

    final result = await gateway.refund(transactionId, amount: amount);
    _paymentController.add(result);
    return result;
  }

  Future<bool> isWalletAvailable() async {
    final walletGateway = _gateways[PaymentMethod.applePay];
    if (walletGateway is MobileWalletGateway) {
      return await walletGateway.isWalletAvailable();
    }
    return false;
  }

  List<PaymentMethod> get availableMethods => _gateways.keys.toList();

  void _ensureInitialized() {
    if (!_initialized) {
      throw PaymentException(
        'PaymentManager not initialized. Call initialize() first.',
        code: 'NOT_INITIALIZED',
      );
    }
  }

  void _validatePaymentRequest(
    PaymentItem item,
    PaymentMethod method,
    CardDetails? card,
  ) {
    final errors = <String>[];

    if (item.price <= 0) {
      errors.add('Price must be greater than 0');
    }

    if (item.id.isEmpty) {
      errors.add('Item ID is required');
    }

    if (method == PaymentMethod.creditCard && card != null) {
      if (!card.isValid) {
        errors.add('Invalid card details');
      }
    }

    if (errors.isNotEmpty) {
      throw PaymentValidationException(errors);
    }
  }

  Future<void> dispose() async {
    for (final gateway in _gateways.values) {
      await gateway.dispose();
    }
    _gateways.clear();
    await _paymentController.close();
    _initialized = false;
  }
}

class PaymentConfig {
  final String? stripePublishableKey;
  final String? backendUrl;
  final List<String>? iapProductIds;
  final bool enableMobileWallet;
  final String? merchantName;

  const PaymentConfig({
    this.stripePublishableKey,
    this.backendUrl,
    this.iapProductIds,
    this.enableMobileWallet = true,
    this.merchantName,
  });
}

// ---- Payment State Provider ----

// lib/payment/providers/payment_provider.dart
import 'package:flutter/foundation.dart';

class PaymentProvider extends ChangeNotifier {
  final PaymentManager _paymentManager = PaymentManager();

  PaymentStatus _status = PaymentStatus.idle;
  PaymentResult? _lastResult;
  String? _errorMessage;
  bool _isProcessing = false;
  List<PaymentResult> _transactionHistory = [];

  PaymentStatus get status => _status;
  PaymentResult? get lastResult => _lastResult;
  String? get errorMessage => _errorMessage;
  bool get isProcessing => _isProcessing;
  List<PaymentResult> get transactionHistory =>
      List.unmodifiable(_transactionHistory);

  Future<void> initialize(PaymentConfig config) async {
    try {
      await _paymentManager.initialize(config: config);

      _paymentManager.paymentStream.listen((result) {
        _transactionHistory.insert(0, result);
        notifyListeners();
      });
    } catch (e) {
      _errorMessage = e.toString();
      notifyListeners();
    }
  }

  Future<PaymentResult> makePayment({
    required PaymentItem item,
    required PaymentMethod method,
    CardDetails? card,
  }) async {
    _isProcessing = true;
    _status = PaymentStatus.processing;
    _errorMessage = null;
    notifyListeners();

    try {
      final result = await _paymentManager.processPayment(
        item: item,
        method: method,
        card: card,
      );

      _lastResult = result;
      _status = result.status;
      _errorMessage = result.errorMessage;
      _isProcessing = false;
      notifyListeners();

      return result;
    } catch (e) {
      _status = PaymentStatus.failed;
      _errorMessage = e.toString();
      _isProcessing = false;
      notifyListeners();

      return PaymentResult(
        transactionId: '',
        status: PaymentStatus.failed,
        amount: item.price,
        currency: item.currency,
        method: method,
        timestamp: DateTime.now(),
        errorMessage: e.toString(),
      );
    }
  }

  Future<PaymentResult> makeSubscription({
    required PaymentItem item,
    required PaymentMethod method,
  }) async {
    _isProcessing = true;
    _status = PaymentStatus.processing;
    notifyListeners();

    try {
      final result = await _paymentManager.processSubscription(
        item: item,
        method: method,
      );

      _lastResult = result;
      _status = result.status;
      _isProcessing = false;
      notifyListeners();

      return result;
    } catch (e) {
      _status = PaymentStatus.failed;
      _errorMessage = e.toString();
      _isProcessing = false;
      notifyListeners();

      return PaymentResult(
        transactionId: '',
        status: PaymentStatus.failed,
        amount: item.price,
        currency: item.currency,
        method: method,
        timestamp: DateTime.now(),
        errorMessage: e.toString(),
      );
    }
  }

  Future<bool> checkWalletAvailability() async {
    return await _paymentManager.isWalletAvailable();
  }

  List<PaymentMethod> get availableMethods =>
      _paymentManager.availableMethods;

  void clearError() {
    _errorMessage = null;
    notifyListeners();
  }

  @override
  void dispose() {
    _paymentManager.dispose();
    super.dispose();
  }
}

