// lib/payment/widgets/payment_button.dart
import 'package:flutter/material.dart';

class PaymentButton extends StatelessWidget {
  final String label;
  final PaymentMethod method;
  final VoidCallback onPressed;
  final bool isLoading;
  final bool enabled;

  const PaymentButton({
    super.key,
    required this.label,
    required this.method,
    required this.onPressed,
    this.isLoading = false,
    this.enabled = true,
  });

  @override
  Widget build(BuildContext context) {
    return SizedBox(
      width: double.infinity,
      height: 56,
      child: ElevatedButton(
        onPressed: enabled && !isLoading ? onPressed : null,
        style: ElevatedButton.styleFrom(
          backgroundColor: _getButtonColor(),
          foregroundColor: Colors.white,
          shape: RoundedRectangleBorder(
            borderRadius: BorderRadius.circular(12),
          ),
          elevation: 2,
        ),
        child:
            isLoading
                ? const SizedBox(
                  width: 24,
                  height: 24,
                  child: CircularProgressIndicator(
                    strokeWidth: 2,
                    valueColor: AlwaysStoppedAnimation<Color>(Colors.white),
                  ),
                )
                : Row(
                  mainAxisAlignment: MainAxisAlignment.center,
                  children: [
                    Icon(_getIcon(), size: 24),
                    const SizedBox(width: 12),
                    Text(
                      label,
                      style: const TextStyle(
                        fontSize: 16,
                        fontWeight: FontWeight.w600,
                      ),
                    ),
                  ],
                ),
      ),
    );
  }

  Color _getButtonColor() {
    switch (method) {
      case PaymentMethod.applePay:
        return Colors.black;
      case PaymentMethod.googlePay:
        return Colors.white;
      case PaymentMethod.stripe:
      case PaymentMethod.creditCard:
        return const Color(0xFF635BFF);
      case PaymentMethod.inAppPurchase:
        return Colors.blue;
    }
  }

  IconData _getIcon() {
    switch (method) {
      case PaymentMethod.applePay:
        return Icons.apple;
      case PaymentMethod.googlePay:
        return Icons.g_mobiledata;
      case PaymentMethod.stripe:
      case PaymentMethod.creditCard:
        return Icons.credit_card;
      case PaymentMethod.inAppPurchase:
        return Icons.shopping_cart;
    }
  }
}

// lib/payment/widgets/card_input_form.dart
class CardInputForm extends StatefulWidget {
  final void Function(CardDetails) onCardDetailsChanged;
  final bool enabled;

  const CardInputForm({
    super.key,
    required this.onCardDetailsChanged,
    this.enabled = true,
  });

  @override
  State<CardInputForm> createState() => _CardInputFormState();
}

class _CardInputFormState extends State<CardInputForm> {
  final _formKey = GlobalKey<FormState>();
  final _numberController = TextEditingController();
  final _expiryController = TextEditingController();
  final _cvcController = TextEditingController();
  final _nameController = TextEditingController();

  @override
  void dispose() {
    _numberController.dispose();
    _expiryController.dispose();
    _cvcController.dispose();
    _nameController.dispose();
    super.dispose();
  }

  void _onFieldChanged() {
    if (_formKey.currentState?.validate() ?? false) {
      final expiry = _expiryController.text.split('/');
      widget.onCardDetailsChanged(
        CardDetails(
          number: _numberController.text.replaceAll(' ', ''),
          expMonth: int.tryParse(expiry[0]) ?? 0,
          expYear: int.tryParse('20${expiry.length > 1 ? expiry[1] : "00"}') ?? 0,
          cvc: _cvcController.text,
          holderName: _nameController.text,
        ),
      );
    }
  }

  @override
  Widget build(BuildContext context) {
    return Form(
      key: _formKey,
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          // Card Number
          TextFormField(
            controller: _numberController,
            enabled: widget.enabled,
            decoration: InputDecoration(
              labelText: 'Card Number',
              hintText: '4242 4242 4242 4242',
              prefixIcon: const Icon(Icons.credit_card),
              border: OutlineInputBorder(
                borderRadius: BorderRadius.circular(12),
              ),
            ),
            keyboardType: TextInputType.number,
            maxLength: 19,
            onChanged: (_) => _onFieldChanged(),
            validator: (value) {
              if (value == null || value.replaceAll(' ', '').length < 13) {
                return 'Enter a valid card number';
              }
              return null;
            },
            inputFormatters: [CardNumberFormatter()],
          ),
          const SizedBox(height: 16),

          Row(
            children: [
              // Expiry
              Expanded(
                child: TextFormField(
                  controller: _expiryController,
                  enabled: widget.enabled,
                  decoration: InputDecoration(
                    labelText: 'MM/YY',
                    hintText: '12/25',
                    border: OutlineInputBorder(
                      borderRadius: BorderRadius.circular(12),
                    ),
                  ),
                  keyboardType: TextInputType.number,
                  maxLength: 5,
                  onChanged: (_) => _onFieldChanged(),
                  validator: (value) {
                    if (value == null || !RegExp(r'^\d{2}/\d{2}$').hasMatch(value)) {
                      return 'MM/YY';
                    }
                    return null;
                  },
                  inputFormatters: [ExpiryDateFormatter()],
                ),
              ),
              const SizedBox(width: 16),

              // CVC
              Expanded(
                child: TextFormField(
                  controller: _cvcController,
                  enabled: widget.enabled,
                  decoration: InputDecoration(
                    labelText: 'CVC',
                    hintText: '123',
                    border: OutlineInputBorder(
                      borderRadius: BorderRadius.circular(12),
                    ),
                  ),
                  keyboardType: TextInputType.number,
                  maxLength: 4,
                  obscureText: true,
                  onChanged: (_) => _onFieldChanged(),
                  validator: (value) {
                    if (value == null || value.length < 3) {
                      return 'Invalid';
                    }
                    return null;
                  },
                ),
              ),
            ],
          ),
          const SizedBox(height: 16),

          // Cardholder Name
          TextFormField(
            controller: _nameController,
            enabled: widget.enabled,
            decoration: InputDecoration(
              labelText: 'Cardholder Name',
              hintText: 'John Doe',
              prefixIcon: const Icon(Icons.person),
              border: OutlineInputBorder(
                borderRadius: BorderRadius.circular(12),
              ),
            ),
            textCapitalization: TextCapitalization.words,
            onChanged: (_) => _onFieldChanged(),
          ),
        ],
      ),
    );
  }
}

// Input formatters
import 'package:flutter/services.dart';

class CardNumberFormatter extends TextInputFormatter {
  @override
  TextEditingValue formatEditUpdate(
    TextEditingValue oldValue,
    TextEditingValue newValue,
  ) {
    final text = newValue.text.replaceAll(' ', '');
    final buffer = StringBuffer();

    for (int i = 0; i < text.length; i++) {
      if (i > 0 && i % 4 == 0) buffer.write(' ');
      buffer.write(text[i]);
    }

    return TextEditingValue(
      text: buffer.toString(),
      selection: TextSelection.collapsed(offset: buffer.length),
    );
  }
}

class ExpiryDateFormatter extends TextInputFormatter {
  @override
  TextEditingValue formatEditUpdate(
    TextEditingValue oldValue,
    TextEditingValue newValue,
  ) {
    final text = newValue.text.replaceAll('/', '');
    final buffer = StringBuffer();

    for (int i = 0; i < text.length; i++) {
      if (i == 2) buffer.write('/');
      buffer.write(text[i]);
    }

    return TextEditingValue(
      text: buffer.toString(),
      selection: TextSelection.collapsed(offset: buffer.length),
    );
  }
}

